using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    #region AddItem Tests

    [TestMethod]
    public void AddItem_SingleItem_ItemIsInCart()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 2, 9.99m);

        // Assert
        var total = _cart.CalculateTotal();
        Assert.AreEqual(19.98m, total);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllItemsInCart()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 1, 10.00m);
        _cart.AddItem("SKU002", 2, 5.00m);
        _cart.AddItem("SKU003", 3, 3.00m);

        // Assert
        var total = _cart.CalculateTotal();
        Assert.AreEqual(29.00m, total);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesQuantity()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);

        // Act
        _cart.AddItem("SKU001", 3, 10.00m);

        // Assert - quantity should be 2+3=5
        var total = _cart.CalculateTotal();
        Assert.AreEqual(50.00m, total);
    }

    [TestMethod]
    public void AddItem_DuplicateSkuDifferentPrice_UsesLatestPrice()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);

        // Act
        _cart.AddItem("SKU001", 1, 15.00m);

        // Assert - quantity=3, price=15
        var total = _cart.CalculateTotal();
        Assert.AreEqual(45.00m, total);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100)]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU001", 1, -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.AddItem(null!, 1, 10.00m));
    }

    #endregion

    #region RemoveItem Tests

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.AddItem("SKU002", 1, 5.00m);

        // Act
        _cart.RemoveItem("SKU001");

        // Assert
        var total = _cart.CalculateTotal();
        Assert.AreEqual(5.00m, total);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("NONEXISTENT"));
    }

    [TestMethod]
    public void RemoveItem_AlreadyRemovedItem_ThrowsKeyNotFoundException()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 10.00m);
        _cart.RemoveItem("SKU001");

        // Act & Assert
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("SKU001"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.RemoveItem(null!));
    }

    #endregion

    #region CalculateTotal Tests

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        // Arrange
        _cart.AddItem("SKU001", 3, 7.50m);

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(22.50m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);
        _cart.AddItem("SKU002", 2, 50.00m);

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(200.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);
        _cart.AddItem("SKU002", 1, 50.00m);
        _cart.RemoveItem("SKU001");

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(50.00m, total);
    }

    #endregion

    #region ApplyCoupon Tests

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE10");
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(90.00m, total);
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE20");
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(80.00m, total);
    }

    [TestMethod]
    [DataRow("INVALID")]
    [DataRow("")]
    [DataRow("save10")]
    [DataRow("SAVE50")]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException(string code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(code));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_ApplySecondCoupon_OverridesFirst()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        // Act
        _cart.ApplyCoupon("SAVE20");
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(80.00m, total);
    }

    #endregion

    #region Combined Scenarios

    [TestMethod]
    public void Combined_AddItemsApplyCouponCalculateTotal_CorrectDiscountedTotal()
    {
        // Arrange
        _cart.AddItem("WIDGET", 2, 25.00m);
        _cart.AddItem("GADGET", 1, 50.00m);

        // Act
        _cart.ApplyCoupon("SAVE10");
        var total = _cart.CalculateTotal();

        // Assert - (2*25 + 1*50) = 100, 10% off = 90
        Assert.AreEqual(90.00m, total);
    }

    [TestMethod]
    public void Combined_AddRemoveApplyCoupon_CorrectTotal()
    {
        // Arrange
        _cart.AddItem("A", 1, 100.00m);
        _cart.AddItem("B", 1, 200.00m);
        _cart.RemoveItem("A");
        _cart.ApplyCoupon("SAVE20");

        // Act
        var total = _cart.CalculateTotal();

        // Assert - 200 * 0.80 = 160
        Assert.AreEqual(160.00m, total);
    }

    [TestMethod]
    public void Combined_EmptyCartWithCoupon_ReturnsZero()
    {
        // Arrange
        _cart.ApplyCoupon("SAVE10");

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void Combined_DuplicateSkuThenCoupon_CorrectTotal()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.AddItem("SKU001", 3, 10.00m); // quantity becomes 5

        // Act
        _cart.ApplyCoupon("SAVE20");
        var total = _cart.CalculateTotal();

        // Assert - 5*10 = 50, 20% off = 40
        Assert.AreEqual(40.00m, total);
    }

    #endregion
}

