1. namespace Store;
2. 
3. public sealed class ShoppingCart
4. {
5.     private readonly Dictionary<string, (int Quantity, decimal Price)> _items = new();
6.     private decimal _discountPercent;
7. 
8.     public void AddItem(string sku, int quantity, decimal price)
9.     {
10.         ArgumentNullException.ThrowIfNull(sku);
11.         if (quantity <= 0) throw new ArgumentOutOfRangeException(nameof(quantity));
12.         if (price < 0) throw new ArgumentOutOfRangeException(nameof(price));
13. 
14.         if (_items.TryGetValue(sku, out var existing))
15.         {
16.             _items[sku] = (existing.Quantity + quantity, price);
17.         }
18.         else
19.         {
20.             _items[sku] = (quantity, price);
21.         }
22.     }
23. 
24.     public void RemoveItem(string sku)
25.     {
26.         ArgumentNullException.ThrowIfNull(sku);
27.         if (!_items.Remove(sku))
28.         {
29.             throw new KeyNotFoundException($"SKU '{sku}' not found in cart.");
30.         }
31.     }
32. 
33.     public decimal CalculateTotal()
34.     {
35.         decimal total = _items.Values.Sum(item => item.Quantity * item.Price);
36.         return total * (1 - _discountPercent / 100m);
37.     }
38. 
39.     public void ApplyCoupon(string code)
40.     {
41.         ArgumentNullException.ThrowIfNull(code);
42.         _discountPercent = code switch
43.         {
44.             "SAVE10" => 10m,
45.             "SAVE20" => 20m,
46.             _ => throw new ArgumentException($"Invalid coupon code: '{code}'.", nameof(code))
47.         };
48.     }
49. }
50.

